let uiLang=localStorage.getItem('fh6_lang')||'ru';
function t(key){return (FH6_I18N[uiLang]&&FH6_I18N[uiLang][key])||(FH6_I18N.en&&FH6_I18N.en[key])||key}
function catLabel(value){return uiLang==='ru'?(FH6_CATEGORY_RU[value]||value||'POI'):(value||'POI')}
function poiDisplayTitle(poi){if(poi&&poi.isCustom)return t('selected_point');return (poi&&poi.title)||t('unknown_poi')}
function setLanguage(lang){uiLang=(lang==='en')?'en':'ru';localStorage.setItem('fh6_lang',uiLang);applyLanguage()}
function applyLanguage(){
  document.documentElement.lang=uiLang;
  document.querySelectorAll('[data-i18n]').forEach(el=>{el.textContent=t(el.dataset.i18n)});
  document.querySelectorAll('[data-i18n-title]').forEach(el=>{el.title=t(el.dataset.i18nTitle)});
  document.querySelectorAll('[data-i18n-placeholder]').forEach(el=>{el.placeholder=t(el.dataset.i18nPlaceholder)});
  document.querySelectorAll('[data-i18n-alt]').forEach(el=>{el.alt=t(el.dataset.i18nAlt)});
  const langSel=document.getElementById('languageSelect');if(langSel)langSel.value=uiLang;
  const cat=document.getElementById('categorySelect');if(cat){for(const opt of cat.options){opt.textContent=opt.value?catLabel(opt.value):t('all_poi')}}
  const phone=document.getElementById('phoneUrl');if(phone&&(!phone.dataset.loaded||phone.textContent===FH6_I18N.en.detecting_ip||phone.textContent===FH6_I18N.ru.detecting_ip))phone.textContent=t('detecting_ip');
  updateHud();updateNearest();renderMarkers();updateNavUi();runSearch(document.getElementById('searchInput')?.value||'');
}

