const FALLBACK_IMG_W=1638,FALLBACK_IMG_H=2048,FALLBACK_SX=6.58487266,FALLBACK_SY=6.60554791,FALLBACK_OX=4594.21749925,FALLBACK_OY=3225.79270983;
const NAV_AUTO_ZOOM_SECONDS=4.0,NAV_AUTO_ZOOM_MIN_METERS=170,NAV_AUTO_ZOOM_HOLD_IN_MS=4200,NAV_AUTO_ZOOM_CHECK_MS=450,NAV_AUTO_ZOOM_MANUAL_COOLDOWN_MS=5500,NAV_AUTO_ZOOM_MIN_ZOOM=15,NAV_AUTO_ZOOM_TOP_MARGIN=128,NAV_AUTO_ZOOM_SIDE_MARGIN=42,NAV_AUTO_ZOOM_BOTTOM_MARGIN=96;

// v0.9.15 compact lower-left nearest POI
let mobileActivePanel=null;
function isMobileLayout(){return window.matchMedia('(max-width:760px), (pointer:coarse)').matches}
function setMobileUiClass(){document.body.classList.toggle('mobileUi',isMobileLayout())}
function setDockActive(panel){document.querySelectorAll('.mobileDockBtn').forEach(btn=>btn.classList.toggle('active',btn.dataset.panel===panel));}
function closeMobilePanels(){
  mobileActivePanel=null;
  document.querySelectorAll('.mobileSheet').forEach(el=>el.classList.remove('mobileOpen'));
  document.getElementById('app').classList.remove('mediaOpen');
  document.getElementById('app').classList.remove('nearestOpen');
  setDockActive(null);
}
function openMobilePanel(panel){
  setMobileUiClass();
  const app=document.getElementById('app');
  const same=mobileActivePanel===panel || (panel==='media'&&app.classList.contains('mediaOpen'));
  closeMobilePanels();
  if(same)return;
  mobileActivePanel=panel;
  setDockActive(panel);
  if(panel==='media'){
    app.classList.remove('mediaCollapsed');
    app.classList.add('mediaOpen');
    return;
  }
  const el=document.querySelector('.mobileSheet[data-mobile-panel="'+panel+'"]');
  if(el)el.classList.add('mobileOpen');
  if(panel==='info'){app.classList.add('nearestOpen');updateNearest();}
  if(panel==='search')setTimeout(()=>document.getElementById('searchInput')?.focus(),70);
}

function isNavTouchLookActive(){return false}
function keepNavigatorFollow(){if(navMode)follow=true;const btn=document.getElementById('followBtn');if(btn)btn.classList.add('active')}
function suspendNavFollow(ms=NAV_TOUCH_LOOK_MS){if(navMode&&follow){navTouchLookUntil=0;keepNavigatorFollow()}}
function centerIfFollowing(){if(follow)centerOnPlayer()}
function setFollowEnabled(value){follow=!!value;const btn=document.getElementById('followBtn');if(btn)btn.classList.toggle('active',follow);if(follow){navTouchLookUntil=0;centerOnPlayer();renderTiles(true);renderPlayer();renderMarkers();renderRouteLine();updateNearest();}}
function toggleNearestOverlay(){
  const app=document.getElementById('app');
  const next=!app.classList.contains('nearestOpen');
  closeMobilePanels();
  app.classList.toggle('nearestOpen',next);
  if(next)updateNearest();
}
function clamp(n,a,b){return Math.max(a,Math.min(b,n))}function scale(){return Math.pow(2,zoom-MAX_ZOOM)}function mapToScreen(mx,my){const s=scale();return{x:mx*s-panX,y:my*s-panY}}function rotatePointAround(px,py,cx,cy,deg){if(!deg)return{x:px,y:py};const rad=deg*Math.PI/180,cos=Math.cos(rad),sin=Math.sin(rad),dx=px-cx,dy=py-cy;return{x:cx+dx*cos-dy*sin,y:cy+dx*sin+dy*cos}}function screenToMap(sx,sy){const a=navAnchor(),deg=navRotationDeg();const u=rotatePointAround(sx,sy,a.x,a.y,-deg);const s=scale();return{x:(u.x+panX)/s,y:(u.y+panY)/s}}function dist(a,b){const dx=a.map_x-b.map_x,dy=a.map_y-b.map_y;return Math.sqrt(dx*dx+dy*dy)}function metersFromMapPx(px){return px/MAP_PX_PER_METER}function mapPxFromMeters(m){return m*MAP_PX_PER_METER}
function initControls(){
  document.getElementById('layerSelect').value=layerId;
  document.getElementById('categorySelect').value=categoryFilter;
  const languageSelect=document.getElementById('languageSelect');
  if(languageSelect){languageSelect.value=uiLang;languageSelect.onchange=e=>setLanguage(e.target.value)}
  const northBtn=document.getElementById('northUpBtn');
  if(northBtn)northBtn.classList.toggle('active',northUp);
  document.getElementById('followBtn').classList.add('active');
  follow=true;
  document.getElementById('followBtn').onclick=()=>setFollowEnabled(!follow);
  document.getElementById('navBtn').onclick=()=>enterNavMode();
  if(northBtn)northBtn.onclick=()=>{setNorthUp(!northUp);lastTileKey='';renderAll(true)};
  document.getElementById('navExitBtn').onclick=()=>exitNavMode();
  document.getElementById('mediaPrevBtn').onclick=()=>sendMediaKey('prev');
  document.getElementById('mediaPlayBtn').onclick=()=>sendMediaKey('playpause');
  document.getElementById('mediaNextBtn').onclick=()=>sendMediaKey('next');
  document.getElementById('mediaVolDownBtn').onclick=()=>sendMediaKey('voldown');
  document.getElementById('mediaVolUpBtn').onclick=()=>sendMediaKey('volup');
  document.getElementById('mediaCollapseBtn')?.addEventListener('click',()=>{const app=document.getElementById('app');app.classList.remove('mediaOpen');app.classList.add('mediaCollapsed');mobileActivePanel=null;setDockActive(null);});
  document.getElementById('navMediaToggleBtn')?.addEventListener('click',()=>openMobilePanel('media'));
  document.getElementById('navInfoToggleBtn')?.addEventListener('click',()=>toggleNearestOverlay());
  document.getElementById('mobileNearestCloseBtn')?.addEventListener('click',()=>document.getElementById('app').classList.remove('nearestOpen'));
  document.querySelectorAll('.mobileDockBtn').forEach(btn=>btn.addEventListener('click',()=>openMobilePanel(btn.dataset.panel)));
  document.querySelectorAll('[data-close-mobile]').forEach(btn=>btn.addEventListener('click',()=>closeMobilePanels()));
  document.getElementById('markersBtn').onclick=()=>{showMarkers=!showMarkers;document.getElementById('markersBtn').classList.toggle('active',showMarkers);renderMarkers()};
  document.getElementById('layerSelect').onchange=e=>{layerId=e.target.value;localStorage.setItem('fh6_layer',layerId);tileLayer.innerHTML="";lastTileKey="";renderTiles(true)};
  document.getElementById('categorySelect').onchange=e=>{categoryFilter=e.target.value;localStorage.setItem('fh6_category',categoryFilter);renderMarkers();updateNearest();runSearch(document.getElementById('searchInput')?.value||'')};
  initSearch();
  applyLanguage();
}
function setNorthUp(value){northUp=!!value;localStorage.setItem('fh6_north_up',northUp?'1':'0');const northBtn=document.getElementById('northUpBtn');if(northBtn)northBtn.classList.toggle('active',northUp);applyMapRotation()}
function setZoom(n,cx=null,cy=null,opts={}){const isAuto=!!(opts&&opts.auto);n=clamp(Math.round(n),MIN_ZOOM,MAX_ZOOM);if(!isAuto)lastManualZoomAt=Date.now();if(n===zoom)return;let anchor;if(cx!==null&&cy!==null){const r0=viewport.getBoundingClientRect();anchor=screenToMap(cx-r0.left,cy-r0.top)}else anchor={x:playerMapX,y:playerMapY};zoom=n;if(!isAuto)localStorage.setItem('fh6_zoom',String(zoom));const r=viewport.getBoundingClientRect(),s=scale();if(cx!==null&&cy!==null){panX=anchor.x*s-(cx-r.left);panY=anchor.y*s-(cy-r.top)}else centerOnPlayer();clampPan();tileLayer.innerHTML="";lastTileKey="";applyMapRotation();renderAll(true)}
function centerOnPlayer(){const a=navAnchor(),s=scale();panX=playerMapX*s-a.x;panY=playerMapY*s-a.y;clampPan();applyMapRotation()}
function clampPan(){const r=viewport.getBoundingClientRect(),s=scale(),ww=MAP_WIDTH*s,hh=MAP_HEIGHT*s;if(ww<=r.width)panX=(ww-r.width)/2;else panX=clamp(panX,0,ww-r.width);if(hh<=r.height)panY=(hh-r.height)/2;else panY=clamp(panY,0,hh-r.height)}
function navAnchor(){const r=viewport.getBoundingClientRect();return{x:r.width/2,y:navMode?r.height*0.68:r.height/2}}
function navRotationDeg(){return (navMode&&follow&&routeTarget&&!northUp)?-(displayHeadingDeg||0):0}
function normalizeAngleDeg(deg){return ((Number(deg)||0)%360+360)%360}
function mapVectorToHeadingDeg(dx,dy){return normalizeAngleDeg(Math.atan2(dx,-dy)*180/Math.PI)}
function updateHeadingFromMotion(mx,my,speedKmh,serverHeadingDeg){let heading=Number(serverHeadingDeg)||0;const now=performance.now();if(lastTelemetryMapX!==null&&lastTelemetryMapY!==null){const dx=mx-lastTelemetryMapX,dy=my-lastTelemetryMapY,step=Math.hypot(dx,dy);if(step>0.45&&(speedKmh||0)>2){heading=mapVectorToHeadingDeg(dx,dy);lastMovementHeadingDeg=heading;lastMovementHeadingAt=now}else if(lastMovementHeadingDeg!==null&&(now-lastMovementHeadingAt)<3500){heading=lastMovementHeadingDeg}}lastTelemetryMapX=mx;lastTelemetryMapY=my;return normalizeAngleDeg(heading)}
function applyMapRotation(){const a=navAnchor(),deg=navRotationDeg();if(mapWorld){mapWorld.style.transformOrigin=`${a.x}px ${a.y}px`;mapWorld.style.transform=`rotate(${deg}deg)`}}

function renderMapFallback(){const img=document.getElementById('mapFallback');if(!img)return;const s=scale();img.style.left=`${(FALLBACK_OX*s-panX).toFixed(1)}px`;img.style.top=`${(FALLBACK_OY*s-panY).toFixed(1)}px`;img.style.width=`${(FALLBACK_IMG_W*FALLBACK_SX*s).toFixed(1)}px`;img.style.height=`${(FALLBACK_IMG_H*FALLBACK_SY*s).toFixed(1)}px`}
function renderTiles(force=false){renderMapFallback();const r=viewport.getBoundingClientRect(),s=scale(),margin=navMode?5:1,x0=Math.floor(panX/TILE_SIZE)-margin,y0=Math.floor(panY/TILE_SIZE)-margin,x1=Math.ceil((panX+r.width)/TILE_SIZE)+margin,y1=Math.ceil((panY+r.height)/TILE_SIZE)+margin,maxTx=Math.ceil((MAP_WIDTH*s)/TILE_SIZE)-1,maxTy=Math.ceil((MAP_HEIGHT*s)/TILE_SIZE)-1,key=[zoom,layerId,x0,y0,x1,y1,Math.round(panX),Math.round(panY)].join(':');if(!force&&key===lastTileKey){applyMapRotation();return}lastTileKey=key;const need=new Set();for(let ty=y0;ty<=y1;ty++)for(let tx=x0;tx<=x1;tx++){if(tx<0||ty<0||tx>maxTx||ty>maxTy)continue;const id=`${zoom}-${tx}-${ty}`;need.add(id);let img=document.getElementById('tile-'+id);if(!img){img=document.createElement('img');img.className='tile';img.id='tile-'+id;img.decoding='async';img.loading='eager';img.src=`/tile/${layerId}/${zoom}/${tx}/${ty}.png`;img.onerror=()=>{img.style.opacity=0};tileLayer.appendChild(img)}img.style.left=`${tx*TILE_SIZE-panX}px`;img.style.top=`${ty*TILE_SIZE-panY}px`}for(const img of Array.from(tileLayer.children))if(!need.has(img.id.replace('tile-','')))img.remove();applyMapRotation()}
function renderPlayer(){if(playerMapX===null||playerMapY===null){if(playerEl)playerEl.style.display='none';return}if(!playerEl){playerEl=document.createElement('div');playerEl.className='player';playerLayer.appendChild(playerEl)}const p=mapToScreen(playerMapX,playerMapY);playerEl.style.display='block';playerEl.style.left=`${p.x}px`;playerEl.style.top=`${p.y}px`}
function populateCategories(){const cats=[...new Set(markers.map(m=>m.category).filter(Boolean))].sort(),sel=document.getElementById('categorySelect');if(!sel)return;for(const o of Array.from(sel.options).slice(1))o.remove();for(const c of cats){let o=document.createElement('option');o.value=c;o.textContent=catLabel(c);sel.appendChild(o)}if(categoryFilter)sel.value=categoryFilter;applyLanguage()}
