function pointSegmentDistance(px,py,ax,ay,bx,by){const vx=bx-ax,vy=by-ay,wx=px-ax,wy=py-ay;const c1=vx*wx+vy*wy;const c2=vx*vx+vy*vy;if(c2<=0)return{d:Math.hypot(px-ax,py-ay),x:ax,y:ay,t:0};let t=c1/c2;t=clamp(t,0,1);const x=ax+vx*t,y=ay+vy*t;return{d:Math.hypot(px-x,py-y),x,y,t}}
